```julia
using LinearAlgebra
T=ComplexF64;d=5;
τ=randn(T);x=randn(T,d);A=randn(T,d,d);
(I - conj(τ)*[1; x[2:end]]*[1; x[2:end]]')*A
LinearAlgebra.reflectorApply!(x,τ,A)
```","reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/55013/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/JuliaLang/julia/issues/55013/timeline","performed_via_github_app":null,"state_reason":null},"comment":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/comments/2217810869","html_url":"https://github.com/JuliaLang/julia/pull/55013#issuecomment-2217810869","issue_url":"https://api.github.com/repos/JuliaLang/julia/issues/55013","id":2217810869,"node_id":"IC_kwDOABkWpM6EMRu1","user":{"login":"dkarrasch","id":26658441,"node_id":"MDQ6VXNlcjI2NjU4NDQx","avatar_url":"https://avatars.githubusercontent.com/u/26658441?v=4","gravatar_id":"","url":"https://api.github.com/users/dkarrasch","html_url":"https://github.com/dkarrasch","followers_url":"https://api.github.com/users/dkarrasch/followers","following_url":"https://api.github.com/users/dkarrasch/following{/other_user}","gists_url":"https://api.github.com/users/dkarrasch/gists{/gist_id}","starred_url":"https://api.github.com/users/dkarrasch/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/dkarrasch/subscriptions","organizations_url":"https://api.github.com/users/dkarrasch/orgs","repos_url":"https://api.github.com/users/dkarrasch/repos","events_url":"https://api.github.com/users/dkarrasch/events{/privacy}","received_events_url":"https://api.github.com/users/dkarrasch/received_events","type":"User","site_admin":false},"created_at":"2024-07-09T13:53:46Z","updated_at":"2024-07-09T13:53:46Z","author_association":"MEMBER","body":"We could add a little doctest to the docstring, as well.","reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/issues/comments/2217810869/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"performed_via_github_app":null}}

